45	  it("should handle multiple items with different modifiers (sword cursed 100+50=150, amulet plain 60, staff enchanted 80+24=104: total 314 base + 5 fee)", () => {
46	    expect(calculatePremium([
47	      { type: "Sword", cursed: true },
48	      { type: "Amulet" },
49	      { type: "Staff", enchantment: 5 }
50	    ])).toBe(319);
